import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote - base premiums
  it("should return 5G premium for empty items list (processing fee only)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote" as const, items: [] },
      ],
    };
    const result = processScenario(scenario);
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("should compute premium for a single plain sword (base + first insurance + fee)", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [
            { type: "sword", material: "steel", enchantment: 0, cursed: false },
          ],
        },
      ],
    };
    const result = processScenario(scenario);
    // base 100 + first insurance 10% of 100 = 10 + fee 5 = 115
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("should compute correct base premium for each main item type (amulet, staff, potion)", () => {
    const makeScenario = (type: string) => ({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote" as const,
          items: [{ type, material: "silver", enchantment: 0, cursed: false }],
        },
      ],
    });
    // amulet: 60 base + 6 first insurance + 5 fee = 71
    expect(processScenario(makeScenario("amulet"))).toEqual({ results: [{ premium: 71 }] });
    // staff: 80 base + 8 first insurance + 5 fee = 93
    expect(processScenario(makeScenario("staff"))).toEqual({ results: [{ premium: 93 }] });
    // potion: 40 base + 4 first insurance + 5 fee = 49
    expect(processScenario(makeScenario("potion"))).toEqual({ results: [{ premium: 49 }] });
  });
  it.todo("should compute base premium for components (25G each)");
  it.todo("should apply block discount for exactly 3 alike components (60G instead of 75G)");
  it.todo("should not apply block discount for component counts other than 3");

  // Quote - item-specific modifiers
  it.todo("should apply 50% cursed surcharge on the cursed item base premium only");
  it.todo("should apply 30% high enchantment surcharge for enchantment level >= 5");

  // Quote - policy-wide modifiers
  it.todo("should apply 20% loyalty discount for customers with >= 2 years");
  it.todo("should apply 15% follow-up contract discount on the second quote");

  // Quote - multi-item and integration
  it.todo("should compute premium for multi-item policy applying item-specific modifiers per item");
  it.todo("should round premium up in MHPCO's favor");
  it.todo("should compute 165G for newcomer with cursed sword (integration example 1)");
  it.todo("should compute 160G for long-standing customer's second contract (integration example 2)");

  // Claim - basic
  it.todo("should apply 100G deductible per damaged item in a claim");
  it.todo("should cap total payout at twice the insurance sum");
  it.todo("should reimburse at 50% for items with enchantment >= 8");
  it.todo("should fully reimburse damage to dragon material items");
  it.todo("should track remaining cap across multiple claims on the same policy");
  it.todo("should round payout down in MHPCO's favor");

  // Error handling
  it.todo("should reject unknown item types with non-zero exit");
  it.todo("should reject negative damage amounts with non-zero exit");
  it.todo("should reject damage entries for items not in the policy");
  it.todo("should reject damage entries exceeding insured item count");
});

