const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export function processScenario(scenario: { steps: Array<{ items?: Array<{ type: string }> }> }): unknown {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const policyBasePremium = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
    const premium = policyBasePremium + policyBasePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

