  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const policyBasePremium = computeItemsBasePremium(items);
    const premium = policyBasePremium + policyBasePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

