export function processScenario(scenario: { steps: Array<{ items?: Item[] }> }): unknown {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const policyBasePremium = computeItemsBasePremium(items);
    const cursedSurcharge = items.reduce((sum, item) => {
      if (item.cursed) {
        return sum + BASE_PREMIUMS[item.type] * CURSED_SURCHARGE_RATE;
      }
      return sum;
    }, 0);
    const premium = policyBasePremium + cursedSurcharge + policyBasePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

