const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: COMPONENT_PREMIUM,
  moonstone: COMPONENT_PREMIUM,
};

function computeItemsBasePremium(items: Array<{ type: string }>): number {
  const counts: Record<string, number> = {};
  for (const item of items) {
    counts[item.type] = (counts[item.type] ?? 0) + 1;
  }
  return Object.entries(counts).reduce((total, [type, count]) => {
    const unitPremium = BASE_PREMIUMS[type];
    if (unitPremium === COMPONENT_PREMIUM && count === COMPONENT_BLOCK_SIZE) {
      return total + COMPONENT_BLOCK_PREMIUM;
    }
    return total + unitPremium * count;
  }, 0);
}

interface Item {
  type: string;
  cursed?: boolean;
  enchantment?: number;
}

function computeItemSurcharge(items: Item[], predicate: (item: Item) => boolean, rate: number): number {
  return items
    .filter(predicate)
    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
}

export function processScenario(scenario: { steps: Array<{ items?: Item[] }> }): unknown {
  const results = scenario.steps.map((step) => {
    const items = step.items ?? [];
    const policyBasePremium = computeItemsBasePremium(items);
    const cursedSurcharge = computeItemSurcharge(items, (item) => !!item.cursed, CURSED_SURCHARGE_RATE);
    const enchantmentSurcharge = computeItemSurcharge(items, (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE_RATE);
    const premium = policyBasePremium + cursedSurcharge + enchantmentSurcharge + policyBasePremium * FIRST_INSURANCE_RATE + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

